import anthropic, json, re
from dataclasses import dataclass

client = anthropic.Anthropic()

@dataclass
class Step:
    id: str
    action: str
    tool: str
    params: dict

def generate_plan(task: str, context: dict) -> list[Step]:
    prompt = f"""Planning agent. Output ONLY JSON:
Task: {task}
Context: {json.dumps(context)}
{{"goal": "...", "steps": [{{"id":"1","action":"...","tool":"...","params":{{}}}}]}}"""
    resp = client.messages.create(
        model="claude-opus-4-5",
        max_tokens=8000,
        thinking={"type": "enabled", "budget_tokens": 5000},
        messages=[{"role": "user", "content": prompt}],
    )
    text = next(b.text for b in resp.content if b.type == "text")
    data = json.loads(re.search(r"\{.*\}", text, re.DOTALL).group())
    return [Step(**s) for s in data["steps"]]

def replan(task: str, failed: Step, error: str, remaining: list[Step]) -> list[Step]:
    prompt = f"""Step failed. Output replacement steps as JSON array.
Failed: {json.dumps(failed.__dict__)}  Error: {error}
Remaining: {json.dumps([s.__dict__ for s in remaining])}
Output ONLY a JSON array."""
    resp = client.messages.create(
        model="claude-opus-4-5",
        max_tokens=4000,
        thinking={"type": "enabled", "budget_tokens": 2000},
        messages=[{"role": "user", "content": prompt}],
    )
    text = next(b.text for b in resp.content if b.type == "text")
    return [Step(**s) for s in json.loads(re.search(r"\[.*\]", text, re.DOTALL).group())]

def execute_step(step: Step) -> dict:
    """Simulated executor — replace with real tool dispatch."""
    if step.tool == "run_query":
        return {"ok": False, "error": "Table 'events' not found"}
    return {"ok": True, "output": f"Executed: {step.action}"}

# Run the pipeline
task = "Audit the application database for missing indexes on the events table"
queue = generate_plan(task, {"db": "postgres://prod-db:5432/app"})

while queue:
    step = queue.pop(0)
    result = execute_step(step)
    if not result["ok"]:
        print(f"Step {step.id} FAILED: {result['error']} — replanning...")
        queue = replan(task, step, result["error"], queue) + queue
    else:
        print(f"Step {step.id} OK: {result['output']}")

print("Pipeline complete.")

# Enabling prompt caching + extended thinking together (Anthropic SDK)
import anthropic

client = anthropic.Anthropic()

SYSTEM_PROMPT = """You are a senior software architect.
Analyze problems thoroughly before recommending solutions.
Always consider security, performance, and maintainability."""  # ~50 tokens here, expand as needed

response = client.messages.create(
    model="claude-opus-4-5",
    max_tokens=12000,
    thinking={
        "type": "enabled",
        "budget_tokens": 8000,
    },
    system=[
        {
            "type": "text",
            "text": SYSTEM_PROMPT,
            "cache_control": {"type": "ephemeral"},  # cache the system prompt
        }
    ],
    messages=[
        {
            "role": "user",
            "content": "Design the database schema for a multi-tenant SaaS application "
                       "supporting 10 000 tenants with row-level security and soft-delete.",
        }
    ],
)

for block in response.content:
    if block.type == "thinking":
        print(f"[Thinking: {len(block.thinking)} chars — developer only]")
    elif block.type == "text":
        print(block.text)

print(f"Cache write tokens: {response.usage.cache_creation_input_tokens}")
print(f"Cache read tokens:  {response.usage.cache_read_input_tokens}")
